#include "../include/arena.h"
#include "../pool_a/tag.h"

#include <stddef.h>
#include <string.h>

static size_t fl_ix(size_t off) {
    return off >> 3;
}

static void fl_clear(Arena *a, size_t off) {
    size_t ix = fl_ix(off);
    a->fl_link_next[ix] = FL_END;
    a->fl_link_prev[ix] = FL_END;
}

void xb1(Arena *a, Block *b) {
    size_t off = b->off;
    size_t ix = fl_ix(off);
    size_t old = a->fl_head.off;
    a->fl_link_next[ix] = old;
    a->fl_link_prev[ix] = FL_END;
    if (old != FL_END) {
        a->fl_link_prev[fl_ix(old)] = off;
    }
    a->fl_head.base = b->base;
    a->fl_head.off = off;
}

void list_remove(Arena *a, Block *b) {
    size_t off = b->off;
    size_t ix = fl_ix(off);
    size_t nxt = a->fl_link_next[ix];
    size_t prv = a->fl_link_prev[ix];
    if (prv != FL_END) {
        a->fl_link_next[fl_ix(prv)] = nxt;
    } else {
        a->fl_head.off = nxt;
    }
    if (nxt != FL_END) {
        a->fl_link_prev[fl_ix(nxt)] = prv;
    }
    fl_clear(a, off);
}

void list_coalesce(Arena *a, Block *b) {
    size_t total = tag_read_size(b);
    /* Forward coalesce */
    size_t off = b->off + total;
    if (off < a->used) {
        Block nb = {b->base, off};
        if (!z_is_flag(&nb)) {
            list_remove(a, &nb);
            total += tag_read_size(&nb);
            xa0(b, total);
        }
    }
    /* Backward coalesce */
    if (b->off > 0) {
        size_t *prev_ftr = (size_t *)(void *)(b->base + b->off - FTR_SIZE);
        size_t prev_total = prev_ftr[0];
        if (prev_total > 0 && prev_total <= b->off) {
            Block pb = {b->base, b->off - prev_total};
            if (!z_is_flag(&pb)) {
                list_remove(a, &pb);
                total += prev_total;
                pb.off = b->off - prev_total;
                xa0(&pb, total);
                *b = pb;
            }
        }
    }
    xb1(a, b);
}

int q8f_blk(Arena *a, Block *oldb, size_t need, size_t *merged_out) {
    size_t old_total = tag_read_size(oldb);
    size_t next_off = oldb->off + old_total;
    size_t ntotal;
    Block nb;
    if (next_off >= a->used) {
        return -1;
    }
    nb.base = oldb->base;
    nb.off = next_off;
    if (z_is_flag(&nb)) {
        return -1;
