static Block *find_fit(Arena *a, size_t need) {
    size_t cur = a->fl_head.off;
    static Block pick;
    while (cur != FL_END) {
        Block b = make_blk(a, cur);
        size_t total = tag_read_size(&b);
        if (total >= need) {
            pick = b;
            return &pick;
        }
        cur = a->fl_link_next[fl_ix(cur)];
    }
    return NULL;
