        if (line[0] == '#' || line[0] == '\n') {
            continue;
        }
        if (sscanf(line, "ALLOC %zu", &sz) == 1) {
            PlanOp *p = &out->ops[out->op_count++];
            p->kind = OP_ALLOC;
            p->size = sz;
            p->index = -1;
        } else if (sscanf(line, "FREE %d", &idx) == 1) {
            PlanOp *p = &out->ops[out->op_count++];
            p->kind = OP_FREE;
            p->index = idx;
        } else if (sscanf(line, "REALLOC %d %zu", &idx, &sz) == 2) {
